  "inlineSchema": "generator client {\n  provider      = \"prisma-client-js\"\n  binaryTargets = [\"native\", \"linux-musl-openssl-3.0.x\"]\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ─── Usuários da plataforma (você e sua equipe) ────────────\nmodel User {\n  id        String   @id @default(uuid())\n  name      String\n  email     String   @unique\n  password  String\n  role      Role     @default(ADMIN)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  alerts Alert[]\n\n  @@map(\"users\")\n}\n\n// ─── Clientes contratantes ────────────────────────────────\nmodel Client {\n  id         String       @id @default(uuid())\n  name       String\n  email      String?\n  phone      String?\n  segment    String?\n  plan       Plan         @default(BASIC)\n  status     ClientStatus @default(ACTIVE)\n  monthlyFee Float        @default(0)\n  notes      String?\n  createdAt  DateTime     @default(now())\n  updatedAt  DateTime     @updatedAt\n\n  bots       Bot[]\n  alerts     Alert[]\n  leads      Lead[]\n  leadStages LeadStage[]\n\n  @@map(\"clients\")\n}\n\n// ─── Bots de cada cliente ─────────────────────────────────\nmodel Bot {\n  id             String    @id @default(uuid())\n  clientId       String\n  name           String\n  channel        Channel   @default(WHATSAPP)\n  status         BotStatus @default(OFFLINE)\n  phoneNumber    String? // Número do WhatsApp conectado\n  messagesTotal  Int       @default(0)\n  messagesToday  Int       @default(0)\n  lastActivityAt DateTime?\n  createdAt      DateTime  @default(now())\n  updatedAt      DateTime  @updatedAt\n\n  client    Client        @relation(fields: [clientId], references: [id], onDelete: Cascade)\n  alerts    Alert[]\n  flows     Flow[] // Fluxos deste bot\n  variables BotVariable[] // Variáveis que o cliente pode editar\n\n  @@map(\"bots\")\n}\n\n// Variáveis editáveis pelo cliente (Textos de saudação, horários, etc)\nmodel BotVariable {\n  id          String   @id @default(uuid())\n  botId       String\n  key         String // ex: \"GREETING_MESSAGE\"\n  value       String // ex: \"Olá! Como posso ajudar?\"\n  description String? // Para exibir no painel do cliente (\"Mensagem de boas vindas\")\n  type        VarType  @default(TEXT) // TEXT, NUMBER, BOOLEAN\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  bot Bot @relation(fields: [botId], references: [id], onDelete: Cascade)\n\n  @@unique([botId, key])\n  @@map(\"bot_variables\")\n}\n\n// ─── Construtor de Fluxos (Builder) ───────────────────────\nmodel Flow {\n  id             String      @id @default(uuid())\n  botId          String\n  name           String\n  isActive       Boolean     @default(false)\n  triggerType    TriggerType @default(KEYWORD) // KEYWORD, DEFAULT, ALWAYS\n  triggerKeyword String? // Se for KEYWORD, qual a palavra chave?\n  createdAt      DateTime    @default(now())\n  updatedAt      DateTime    @updatedAt\n\n  bot   Bot    @relation(fields: [botId], references: [id], onDelete: Cascade)\n  nodes Node[]\n  edges Edge[]\n\n  @@map(\"flows\")\n}\n\n// Blocos do construtor\nmodel Node {\n  id        String   @id // ID gerado pelo React Flow no frontend\n  flowId    String\n  type      NodeType // MESSAGE, QUESTION, CONDITION, ACTION, etc\n  positionX Float\n  positionY Float\n  data      Json // Dados específicos do nó (texto da msg, etc)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  flow Flow @relation(fields: [flowId], references: [id], onDelete: Cascade)\n\n  @@map(\"nodes\")\n}\n\n// Conexões entre blocos\nmodel Edge {\n  id           String   @id // ID gerado pelo React Flow\n  flowId       String\n  sourceNodeId String // ID do Node origem\n  targetNodeId String // ID do Node destino\n  sourceHandle String? // Para condições (true/false, opções)\n  createdAt    DateTime @default(now())\n\n  flow Flow @relation(fields: [flowId], references: [id], onDelete: Cascade)\n\n  @@map(\"edges\")\n}\n\n// ─── CRM do Cliente ───────────────────────────────────────\n\n// Fases do Funil (Kanban)\nmodel LeadStage {\n  id        String   @id @default(uuid())\n  clientId  String\n  name      String // Ex: \"Novo\", \"Em Atendimento\", \"Agendado\", \"Fechado\"\n  order     Int // Ordem no Kanban\n  color     String? // Cor da coluna\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  client Client @relation(fields: [clientId], references: [id], onDelete: Cascade)\n  leads  Lead[]\n\n  @@map(\"lead_stages\")\n}\n\nmodel Lead {\n  id          String    @id @default(uuid())\n  clientId    String\n  stageId     String? // Pode não ter stage inicialmente\n  name        String\n  phone       String?\n  email       String?\n  value       Float? // Valor potencial do lead\n  notes       String?\n  lastContact DateTime?\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n\n  client   Client     @relation(fields: [clientId], references: [id], onDelete: Cascade)\n  stage    LeadStage? @relation(fields: [stageId], references: [id])\n  messages Message[] // Histórico de conversa\n\n  @@map(\"leads\")\n}\n\n// Histórico de mensagens do Inbox\nmodel Message {\n  id        String   @id @default(uuid())\n  leadId    String\n  content   String\n  fromBot   Boolean  @default(false) // true = enviada pelo bot/cliente, false = recebida do lead\n  createdAt DateTime @default(now())\n\n  lead Lead @relation(fields: [leadId], references: [id], onDelete: Cascade)\n\n  @@map(\"messages\")\n}\n\n// ─── Alertas ─────────────────────────────\nmodel Alert {\n  id         String      @id @default(uuid())\n  botId      String\n  clientId   String\n  userId     String?\n  severity   Severity    @default(ERROR)\n  title      String\n  message    String\n  status     AlertStatus @default(OPEN)\n  resolvedAt DateTime?\n  createdAt  DateTime    @default(now())\n  updatedAt  DateTime    @updatedAt\n\n  bot    Bot    @relation(fields: [botId], references: [id], onDelete: Cascade)\n  client Client @relation(fields: [clientId], references: [id], onDelete: Cascade)\n  user   User?  @relation(fields: [userId], references: [id])\n\n  @@map(\"alerts\")\n}\n\n// ─── Enums ────────────────────────────────────────────────\nenum Role {\n  ADMIN\n  VIEWER\n}\n\nenum Plan {\n  BASIC\n  PRO\n  PREMIUM\n}\n\nenum ClientStatus {\n  ACTIVE\n  INACTIVE\n  SUSPENDED\n}\n\nenum BotStatus {\n  ONLINE\n  OFFLINE\n  ERROR\n}\n\nenum Channel {\n  WHATSAPP\n  INSTAGRAM\n  WEBSITE\n  TELEGRAM\n}\n\nenum Severity {\n  INFO\n  WARNING\n  ERROR\n  CRITICAL\n}\n\nenum AlertStatus {\n  OPEN\n  RESOLVED\n  IGNORED\n}\n\nenum TriggerType {\n  KEYWORD\n  DEFAULT // Mensagem padrão para qualquer texto caso não caia em keyword\n  ALWAYS // Executa sempre\n}\n\nenum NodeType {\n  MESSAGE\n  QUESTION\n  CONDITION\n  DELAY\n  HTTP_REQUEST\n  UPDATE_LEAD\n}\n\nenum VarType {\n  TEXT\n  NUMBER\n  BOOLEAN\n}\n",
